INSERT INTO sert_core.exception_summaries (rule_key, exception, exception_count, score, reason)
VALUES ('ALLOW_DUPLICATE_SUBMISSIONS', '“Allow Duplicate Page Submissions” is enabled for the listed page(s) by design because repeated submits do not create duplicate database changes. The submit action is used for non-destructive processing only (for example, refresh, navigation, or server-side logic that does not perform inserts, or is otherwise idempotent), and any DML that could be triggered is protected by server-side validation/keys to prevent duplicate records. Disabling duplicate submissions here would not improve security and would negatively affect the intended user flow.', 39, 5, 'The justification directly addresses the misconfiguration concern with specific facts showing why the flagged condition is acceptable, mitigated, or not applicable here. It gives concrete security or design context that makes the exception credible to a reviewer.');
