INSERT INTO sert_core.exception_summaries (rule_key, exception, exception_count, score, reason)
VALUES ('APPLICATION_PROCESS_SQLI', 'False Flag: URL parameters are getting flagged ("&session=")', 1, 5, 'The justification directly addresses the SQL injection concern by explaining why the flagged pattern does not result in executable, user-influenced SQL. It gives a concrete false-positive or mitigation rationale that a security reviewer can validate.');
INSERT INTO sert_core.exception_summaries (rule_key, exception, exception_count, score, reason)
VALUES ('BUTTON_AUTHZ_INCONSISTENCY', 'The SERT Advisor finding “Button Authorization Inconsistency” is not applicable for the listed components. The page is protected by an Authorization Scheme and the referenced buttons are configured with the same Authorization Scheme; the report appears to be a false positive. In addition, access to the button is inherently constrained by page access, since a user must already satisfy authentication and page authorization before the button can be rendered or invoked.', 21, 5, 'The justification directly addresses the access control concern by explaining how equivalent or stronger authorization is enforced at the relevant boundary. It gives enough context to show the finding is a credible false positive or acceptable-by-design case.');
