INSERT INTO sert_core.exception_summaries (rule_key, exception, exception_count, score, reason)
VALUES ('DYNAMIC_CONTENT_CONTAINS_BINDS', 'These Dynamic Content regions intentionally use bind variables and server-side PL/SQL to build HTML for runtime status and log output (for example, “no job selected”, job identifiers, and the tail of an ingestion log). This is display-only functionality to improve UX and does not create an execution path for script injection. Any values that originate from page items or external responses are treated as untrusted and are explicitly output-escaped using APEX_ESCAPE.HTML (and APEX_ESCAPE.HTML_ATTRIBUTE where applicable) before being concatenated into HTML. Bind variables are used only to parameterize the output and service calls, and the rendered content is controlled and sanitized, so this SERT finding is accepted for these components.', 2, 5, 'The justification directly addresses the XSS concern by explaining that untrusted content is escaped, sanitized, or otherwise not rendered in an executable way. It provides concrete mitigation detail that makes the exception credible.');
INSERT INTO sert_core.exception_summaries (rule_key, exception, exception_count, score, reason)
VALUES ('DYNAMIC_CONTENT_CONTAINS_BINDS', 'Acknowledge the risk and leave the code as is. The code is already escaped. False positive? apex_lang.message (            ''APEX.FEATURE.ACL.BULK_USER.CREATE_CONFIRM'',            apex_escape.html(:P10014_VALID_COUNT),            apex_escape.html(:P10014_ROLE)', 1, 5, 'The justification directly addresses the XSS concern by explaining that untrusted content is escaped, sanitized, or otherwise not rendered in an executable way. It provides concrete mitigation detail that makes the exception credible.');
INSERT INTO sert_core.exception_summaries (rule_key, exception, exception_count, score, reason)
VALUES ('DYNAMIC_CONTENT_SQLI', 'False Flag: URL parameters are getting flagged ("&URLD=")', 1, 5, 'The justification directly addresses the SQL injection concern by explaining why the flagged pattern does not result in executable, user-influenced SQL. It gives a concrete false-positive or mitigation rationale that a security reviewer can validate.');
INSERT INTO sert_core.exception_summaries (rule_key, exception, exception_count, score, reason)
VALUES ('DYNAMIC_CONTENT_SQLI', 'False Flag: URL parameters are getting flagged ("&session=", "&share_id=") and REGEXP/Replace functions are getting flagged ("f\?p=&APP_ID\.:", "&HC\.", "&SESSION. > replaced by :APP_SESSION")', 1, 5, 'The justification directly addresses the SQL injection concern by explaining why the flagged pattern does not result in executable, user-influenced SQL. It gives a concrete false-positive or mitigation rationale that a security reviewer can validate.');
INSERT INTO sert_core.exception_summaries (rule_key, exception, exception_count, score, reason)
VALUES ('INTERACTIVE_REPORT_COLUMN_AUTHZ_INCONSISTENCY', 'This “Interactive Report Column Authorization Inconsistency” finding is not applicable for the listed components. The affected pages are protected by the configured Authorization Scheme, and the referenced report columns are not used as an independent access control boundary. A review of the page and component settings confirms the same Authorization Scheme is applied as intended. The report output appears to be a SERT false positive, and no unintended access is introduced because the page-level authorization remains the controlling security check.', 6, 5, 'The justification directly addresses the access control concern by explaining how equivalent or stronger authorization is enforced at the relevant boundary. It gives enough context to show the finding is a credible false positive or acceptable-by-design case.');
INSERT INTO sert_core.exception_summaries (rule_key, exception, exception_count, score, reason)
VALUES ('ERROR_HANDLING_FUNCTION', 'No additional Error handling needed as there is no input data traffic from the users. Read only or mac some info input.', 1, 4, 'The explanation is clearly relevant to the misconfiguration concern and provides a plausible mitigation or false-positive basis. It is strong overall, but it would be more defensible with one more concrete detail about the control or scope.');
INSERT INTO sert_core.exception_summaries (rule_key, exception, exception_count, score, reason)
VALUES ('HIDDEN_ITEM_VALUE_PROTECTED', 'Multiple hidden items are intentionally not Value Protected because they are used as temporary runtime placeholders to pass non-sensitive values between Dynamic Actions, JavaScript, and AJAX/PL/SQL callbacks. These items are not used for authentication, authorization, or other security decisions, and all server-side processes validate input values and enforce access checks independently.', 22, 4, 'The explanation is clearly relevant to the misconfiguration concern and provides a plausible mitigation or false-positive basis. It is strong overall, but it would be more defensible with one more concrete detail about the control or scope.');
INSERT INTO sert_core.exception_summaries (rule_key, exception, exception_count, score, reason)
VALUES ('ITEM_SESSION_STATE_PROTECTION_LEVEL', 'On Page nn (page name), items [item_names] are intentionally configured with Session State Protection = Unrestricted because they are populated and updated at runtime by page Dynamic Actions and AJAX callbacks as part of the tool execution flow. These items act only as transient state holders for request/response payloads and UI rendering, they do not store credentials or privileged flags, and they are not used for authentication or authorization decisions. All server-side processes that consume these values validate inputs and enforce access checks independently, so restricting SSP would break required functionality without improving security.', 5, 4, 'The explanation is clearly relevant to the misconfiguration concern and provides a plausible mitigation or false-positive basis. It is strong overall, but it would be more defensible with one more concrete detail about the control or scope.');
INSERT INTO sert_core.exception_summaries (rule_key, exception, exception_count, score, reason)
VALUES ('ITEM_SESSION_STATE_PROTECTION_LEVEL', 'On the ACE Assistant Chat page, the flagged items must remain Session State Protection = Unrestricted because their values are updated at runtime by Dynamic Actions and AJAX callbacks as part of the chat flow while the user is already on the page. These items function only as transient client-side state for UI updates and request/response handling, they do not store credentials or privileged flags, and they are not used to make authentication or authorization decisions. All server-side processes that consume these values validate inputs and enforce access checks independently, so restricting SSP would break required chat functionality without improving security.', 3, 4, 'The explanation is clearly relevant to the misconfiguration concern and provides a plausible mitigation or false-positive basis. It is strong overall, but it would be more defensible with one more concrete detail about the control or scope.');
INSERT INTO sert_core.exception_summaries (rule_key, exception, exception_count, score, reason)
VALUES ('RUN_AUTHORIZATION_ON_PUBLIC_PAGES', 'This application does not expose public pages. All pages require the configured authentication scheme and are protected by page-level authorization, so “Run Authorization on Public Pages” is not applicable here. Review confirms there are no intended unauthenticated entry points in this app, and access is always enforced before any page processing is executed.', 1, 4, 'The explanation is clearly relevant to the misconfiguration concern and provides a plausible mitigation or false-positive basis. It is strong overall, but it would be more defensible with one more concrete detail about the control or scope.');
