INSERT INTO sert_core.exception_summaries (rule_key, exception, exception_count, score, reason)
VALUES ('INTERACTIVE_REPORT_COLUMN_ESCAPED', 'This page is a read-only component provided by Oracle APEX to display user access patterns. The underlying data is sourced directly from APEX internal tables, which are system-managed and automatically populated based on application usage.  In this specific case, enabling HTML escaping on the ''HOURS'' column impacts the intended rendering of the data. The column output includes formatting that is interpreted by the UI layer; escaping it causes the styles to break and results in a less readable presentation of the statistical information.  Since the data originates from trusted, system-generated APEX sources (not user input), and the page is strictly read-only with no user interaction or data manipulation, the risk associated with not escaping this column is minimal, while the usability impact of escaping is significant.', 1, 1, 'The explanation does not credibly address the XSS risk and does not show a concrete escaping, sanitization, or false-positive basis. It is too vague or incomplete to support the exception.');
